  partialPixelStride?: number;
  partialStage?: DecodeStage;
}

export interface MsgEncodeError {
  type: "encode_error";
  sessionId: string;
  code: string;        // <-- should be JxlErrorCode
  message: string;
}

constructor(
  code: JxlErrorCode,
  message: string,
  opts?: { sessionId?: string; partial?: DecodeFrameEvent; cause?: unknown },
) {
  super(message, opts?.cause !== undefined ? { cause: opts.cause } : undefined);
  this.name = "JxlError";
  this.code = code;
  if (opts?.sessionId !== undefined) this.sessionId = opts.sessionId;
  if (opts?.partial !== undefined) this.partial = opts.partial;
  if (opts?.cause !== undefined) this.cause = opts.cause;  // redundant
}

